 			hflag = 0;
@@ -188,12 +191,16 @@
 		if (vfslist != NULL) {
 			maxwidth = 0;
 			for (i = 0; i < mntsize; i++) {
+				if (lflag && !(mntbuf[i].f_flags & MNT_LOCAL))
+					continue;
 				width = strlen(mntbuf[i].f_mntfromname);
 				if (width > maxwidth)
 					maxwidth = width;
 			}
 		}
 		for (i = 0; i < mntsize; i++) {
+			if (lflag && !(mntbuf[i].f_flags & MNT_LOCAL))
+				continue;
 			if (aflag || (mntbuf[i].f_flags & MNT_IGNORE) == 0)
 				prtstat(&mntbuf[i], maxwidth);
 		}
@@ -203,7 +210,7 @@
 	for (; *argv; argv++) {
 		if (stat(*argv, &stbuf) < 0) {
 			err = errno;
-			if ((mntpt = getmntpt(*argv)) == 0) {
+			if ((mntpt = getmntpt(*argv)) == NULL) {
 				warn("%s", *argv);
 				rv = 1;
 				continue;
@@ -232,7 +239,9 @@
 					continue;
 				} else if (statfs(mntpt, &statfsbuf) == 0) {
 					statfsbuf.f_mntonname[0] = '\0';
-					prtstat(&statfsbuf, maxwidth);
+					if (!lflag ||
+					    (statfsbuf.f_flags & MNT_LOCAL))
+						prtstat(&statfsbuf, maxwidth);
 				} else {
 					warn("%s", *argv);
 					rv = 1;
@@ -255,7 +264,8 @@
 		}
 		if (argc == 1)
 			maxwidth = strlen(statfsbuf.f_mntfromname) + 1;
-		prtstat(&statfsbuf, maxwidth);
+		if (!lflag || (statfsbuf.f_flags & MNT_LOCAL))
+			prtstat(&statfsbuf, maxwidth);
 	}
 	return (rv);
 }
@@ -289,12 +299,15 @@
 	int i, j;
 	struct statfs *mntbuf;

-	if (vfslist == NULL)
+	if (!lflag && (vfslist == NULL))
 		return (nflag ? mntsize : getmntinfo(mntbufp, MNT_WAIT));

 	mntbuf = *mntbufp;
 	for (j = 0, i = 0; i < mntsize; i++) {
-		if (checkvfsname(mntbuf[i].f_fstypename, vfslist))
+		if (lflag && !(mntbuf[i].f_flags & MNT_LOCAL))
+			continue;
+		if ((vfslist != NULL) &&
+		    checkvfsname(mntbuf[i].f_fstypename, vfslist))
 			continue;
 		if (!nflag)
 			(void)statfs(mntbuf[i].f_mntonname,&mntbuf[j]);
@@ -462,7 +475,7 @@
 	sfsp = &statfsbuf;
 	sfsp->f_type = 1;
 	strcpy(sfsp->f_fstypename, "ufs");
-	sfsp->f_flags = 0;
+	sfsp->f_flags = MNT_LOCAL;
 	sfsp->f_bsize = sblock.fs_fsize;
 	sfsp->f_iosize = sblock.fs_bsize;
 	sfsp->f_blocks = sblock.fs_dsize;
@@ -506,6 +519,6 @@
 {

